body:
I tried to synthesize the module below in order to obtain a json and then get the diagram from the json file. The system verilog code is shown below together with the diagram obtained
```
module hcd(input [1:7] i_cded,
        output logic [1:7] o_cded); 
        
 integer syndval ;
 function [2:0] synd (input [1:7] cw); 
    begin 
       synd[0] = cw[5] ^ cw[1] & cw[1] 
            ^ cw[3] ^ cw[7]; 
       synd[1] = cw[6] ^ cw[7] ^ cw[3]
            ^ cw[2]; 
       synd[2] = cw[5] ^ cw[4] ^ cw[6] 
            ^ cw[7]; 
     end 
 endfunction 
 
 always @(*) begin 
    o_cded = i_cded; 
    syndval = synd (i_cded); 
    if(syndval == 3'b0) begin end 
    else begin 
        o_cded[syndval] = ~i_cded[syndval]; 
    end 
 end 
endmodule
```
